#!/usr/bin/env python3
"""gRPC KV Store server."""

import time
from concurrent import futures

import grpc

import kv_store_pb2
import kv_store_pb2_grpc


class Server(kv_store_pb2_grpc.KVStoreServicer):
    """KVStore gRPC servicer backed by a Python dict."""

    def __init__(self):
        self._store: dict[str, int] = {}

    def GetVal(self, request, context):
        val = self._store.get(request.key, 0)
        return kv_store_pb2.GetValResponse(val=val)

    def SetVal(self, request, context):
        self._store[request.key] = request.value
        return kv_store_pb2.SetValResponse(val=request.value)


def serve() -> None:
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    kv_store_pb2_grpc.add_KVStoreServicer_to_server(Server(), server)
    server.add_insecure_port("[::]:5328")
    server.start()
    print("Server started on port 5328")
    try:
        while True:
            time.sleep(3600)
    except KeyboardInterrupt:
        server.stop(0)


if __name__ == "__main__":
    serve()

